def process_job(job_data: Any) -> None:
    if isinstance(job_data, dict):
        job_type = job_data.get('type', 'unknown')
        logging.info(f'Processing job type: {job_type}')
        
        if job_type == 'data_processing':
            process_data_job(job_data)
        elif job_type == 'report_generation':
            process_report_job(job_data)
        elif job_type == 'batch_operation':
            process_batch_job(job_data)
        else:
            logging.warning(f'Unknown job type: {job_type}')
            process_generic_job(job_data)
    elif isinstance(job_data, list):
        logging.info(f'Processing list of {len(job_data)} items')
        for item in job_data:
            process_job(item)
    else:
        logging.info(f'Processing custom object: {type(job_data).__name__}')
        process_custom_object(job_data)


def process_data_job(job_data: dict) -> None:
    logging.info('Processing data job')
    data = job_data.get('data', [])
    operation = job_data.get('operation', 'transform')
    
    logging.info(f'Data job - Operation: {operation}, Records: {len(data)}')
    
    if operation == 'transform':
        transformed_data = [transform_record(record) for record in data]
        logging.info(f'Transformed {len(transformed_data)} records')
    elif operation == 'aggregate':
        result = aggregate_data(data)
        logging.info(f'Aggregation result: {result}')
    elif operation == 'filter':
        criteria = job_data.get('criteria', {})
        filtered_data = [record for record in data if matches_criteria(record, criteria)]
        logging.info(f'Filtered to {len(filtered_data)} records')


def process_report_job(job_data: dict) -> None:
    logging.info('Processing report generation job')
    report_type = job_data.get('report_type', 'summary')
    parameters = job_data.get('parameters', {})
    
    logging.info(f'Generating {report_type} report with parameters: {parameters}')
    
    report_data = generate_report(report_type, parameters)
    logging.info(f'Report generated successfully')


def process_batch_job(job_data: dict) -> None:
    logging.info('Processing batch operation job')
    operations = job_data.get('operations', [])
    
    logging.info(f'Executing {len(operations)} batch operations')
    
    for idx, operation in enumerate(operations):
        logging.info(f'Executing operation {idx + 1}/{len(operations)}')
        execute_operation(operation)
    
    logging.info('Batch operations completed')


