def process_custom_object(obj: Any) -> None:
    logging.info(f'Processing custom object of type: {type(obj).__name__}')
    
    if hasattr(obj, 'process'):
        obj.process()
        logging.info('Called process method on object')
    elif hasattr(obj, 'execute'):
        obj.execute()
        logging.info('Called execute method on object')
    else:
        logging.info(f'Object attributes: {dir(obj)}')


def transform_record(record: Any) -> Any:
    if isinstance(record, dict):
        return {k: str(v).upper() if isinstance(v, str) else v for k, v in record.items()}
    return record


def aggregate_data(data: list) -> dict:
    return {
        'count': len(data),
        'types': list(set(type(item).__name__ for item in data))
    }


def matches_criteria(record: Any, criteria: dict) -> bool:
    if not isinstance(record, dict):
        return True
    
    for key, value in criteria.items():
        if key not in record or record[key] != value:
            return False
    return True


def generate_report(report_type: str, parameters: dict) -> dict:
    return {
        'report_type': report_type,
        'generated_at': 'timestamp',
        'parameters': parameters,
        'status': 'completed'
    }


def execute_operation(operation: dict) -> None:
    op_type = operation.get('type', 'unknown')
    logging.info(f'Executing operation: {op_type}')